import { log2 } from 'math';

function solve(weight) {
    const n = weight.length;
    if (n === 0) return 0;

    // Precompute log table
    const log_table = new Array(n + 1);
    log_table[0] = -1;
    for (let i = 1; i <= n; i++) {
        log_table[i] = log_table[i >> 1] + 1;
    }

    // Build sparse table
    const maxLog = Math.floor(log2(n)) + 1;
    const st = new Array(n);
    for (let i = 0; i < n; i++) {
        st[i] = new Array(maxLog).fill(0);
        st[i][0] = weight[i];
    }

    for (let j = 1; j < maxLog; j++) {
        for (let i = 0; i + (1 << j) - 1 < n; i++) {
            st[i][j] = Math.max(st[i][j - 1], st[i + (1 << (j - 1))][j - 1]);
        }
    }

    // Function to get max in range [l, r]
    function get_max(l, r) {
        const length = r - l + 1;
        const k = log_table[length];
        return Math.max(st[l][k], st[r - (1 << k) + 1][k]);
    }

    // Dynamic programming
    const dp = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        const target = weight[i - 1];
        let low = 0, high = i - 1;
        let res = -1;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            const current_max = get_max(mid, i - 1);
            if (current_max > target) {
                res = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        if (res !== -1) {
            dp[i] = Math.max(dp[i - 1], dp[res] + 1);
        } else {
            dp[i] = dp[i - 1];
        }
    }

    return dp[n];
}
