function solve(weight) {
    let count = 0;
    let start = 0;
    let currentMax = 0;
    for (let i = 0; i < weight.length; i++) {
        if (start <= i) {
            currentMax = Math.max(currentMax, weight[i]);
        }
        if (currentMax > weight[i]) {
            count++;
            start = i + 1;
            currentMax = 0;
        }
    }
    return count;
}
